<!-- MyPage.vue -->
<template>
    <div>
        <MySubHeader :handleResumeButton="handleResumeButton" :handleIntroButton="handleIntroButton" />
        <div v-if="subMenu === 'resume'">
            <Resume />
        </div>
        <div v-else>
            <SelfIntro />
        </div>
        <MyFooter />
    </div>
</template>
  
<script>
import MySubHeader from '../components/MySubHeader.vue';
import Resume from '../components/VueResume.vue';
import SelfIntro from '../components/SelfIntro.vue';
import MyFooter from '../components/MyFooter.vue';

export default {
    components: {
        MySubHeader,
        Resume,
        SelfIntro,
        MyFooter,
    },
    data() {
        return {
            subMenu: 'resume',
        };
    },
    methods: {
        handleResumeButton() {
            this.subMenu = 'resume';
        },
        handleIntroButton() {
            this.subMenu = 'intro';
        },
    },
};
</script>
  
<style scoped>
