import { createWebHistory, createRouter } from "vue-router";
import HomeCmt from "../components/HomeCmt.vue";
import MyPageCmt from "../components/MyPageCmt.vue";
import VueProfile from "../components/VueProfile.vue"
import VueLogin from "../components/VueLogin.vue"
const routes = [
    // 라우터 설정
    {
        path: "/", // 라우터
        component: HomeCmt,
    },
    {
        path: "/mypage",
        component: MyPageCmt,
    },
    {
        path: "/profile",
        component: VueProfile,
    },
    {
        path: "/login",
        component: VueLogin,
    },
];
const router = createRouter({
    // 라우트 생성
    history: createWebHistory(),
    routes,
});
export default router;

